import { CommonModule } from '@angular/common';
import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { GiftModel, AddGift } from '../../Models/Gift';
import { Router, NavigationEnd } from '@angular/router';
import { Observable, filter } from 'rxjs';
import { DataViewModule } from 'primeng/dataview';
import { TagModule } from 'primeng/tag';
import { SelectButtonModule } from 'primeng/selectbutton';
import { ButtonModule } from 'primeng/button';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { DialogModule } from 'primeng/dialog';
import { Category } from '../../Models/Category';
import { AuthorService } from '../../Services/AutorService';
import { PaginatorModule } from 'primeng/paginator';
import { InputTextModule } from 'primeng/inputtext';
import { GiftsService } from '../../Services/GiftsService';
import { CategoryService } from '../../Services/CategoryService';
import jwtDecode from 'jwt-decode';
import { CartService } from '../../Services/CartService';
import { DonorService, Donor } from '../../Services/DonorService';
import { FileUploadModule } from 'primeng/fileupload';

@Component({
  selector: 'app-all-gifts-comp',
  standalone: true,
  imports: [
    CommonModule,
    FileUploadModule,
    FormsModule,
    DataViewModule,
    SelectButtonModule,
    TagModule,
    ButtonModule,
    ProgressSpinnerModule,
    DialogModule,
    PaginatorModule,
    InputTextModule
  ],
  templateUrl: './all-gifts-comp.html',
  styleUrl: './all-gifts-comp.scss',
})
export class AllGiftsComp implements OnInit {
  gifts$!: Observable<GiftModel[]>;
  categories$!: Observable<Category[]>;

  allGifts: GiftModel[] = [];
  pagedGifts: GiftModel[] = [];
  allCategories: Category[] = [];

  // donors
  allDonors: { id: number; fullName: string }[] = [];

  isAdmin: boolean = false;
  displayEditDialog: boolean = false;
  displayAddDialog: boolean = false;

  selectedGiftForEdit: any = {};
  newGift: AddGift = { Name: '', Description: '', CategoryId: 1, TicketPrice: 10, Image: '', DonorId: 1 };

  first: number = 0;
  rows: number = 6;

  isLoading: boolean = false;
  errorMessage: string = '';
  cartUserId: number | null = null;

  constructor(
    private giftService: GiftsService,
    private donorService: DonorService,
    private authorService: AuthorService,
    private categoryService: CategoryService,
    private router: Router,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit() {
    this.checkAdminStatus();
    this.loadGifts();
    this.loadCategories();
    this.loadDonors();

    if (typeof window !== 'undefined') {
      const token = window.localStorage.getItem('authToken');
      if (token) {
        try {
          const decodedToken: any = jwtDecode(token);
          const key = 'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier';
          this.cartUserId = decodedToken[key];
        } catch (error) {
          console.error('Invalid token:', error);
        }
      }
    }

    this.router.events.pipe(filter(event => event instanceof NavigationEnd)).subscribe(() => {
      this.loadGifts();
      this.checkAdminStatus();
    });
  }

  checkAdminStatus() {
    this.isAdmin = this.authorService.isManager();
  }

  // ---------- Donors ----------
  loadDonors() {
    this.donorService.getAllDonors().subscribe({
      next: (data: Donor[]) => {
        this.allDonors = data.map(d => ({ id: d.id, fullName: d.name }));
        if (!this.newGift.DonorId && this.allDonors.length > 0) {
          this.newGift.DonorId = this.allDonors[0].id;
        }
        this.cdr.detectChanges();
      },
      error: (err) => console.error('Error loading donors', err)
    });
  }

  // ---------- Categories ----------
  loadCategories() {
    this.categories$ = this.categoryService.getCategories();
    this.categories$.subscribe({
      next: (data) => {
        this.allCategories = data;
        this.cdr.detectChanges();
      },
      error: (err) => console.error('Error loading categories', err)
    });
  }

  // ---------- Gifts ----------
  loadGifts() {
    this.gifts$ = this.giftService.getGifts();
    this.gifts$.subscribe({
      next: (data) => {
        this.allGifts = data;
        this.updatePage();
        this.cdr.detectChanges();
      },
      error: (err) => console.error('Error loading gifts', err)
    });
  }

  updatePage() {
    this.pagedGifts = this.allGifts.slice(this.first, this.first + this.rows);
  }

  onPageChange(event: any) {
    this.first = event.first;
    this.rows = event.rows;
    this.updatePage();
  }

  // ---------- Add Gift ----------
  openAddGiftDialog() {
    this.errorMessage = '';
    this.newGift = { Name: '', Description: '', CategoryId: 1, TicketPrice: 10, Image: '', DonorId: this.allDonors.length > 0 ? this.allDonors[0].id : 1 };
    this.displayAddDialog = true;
  }

  onUpload(event: any, isEdit: boolean = false) {
    if (event.files && event.files.length > 0) {
      const file = event.files[0];
      if (isEdit) {
        this.selectedGiftForEdit.Image = file.name;
      } else {
        this.newGift.Image = file.name;
      }
      this.cdr.detectChanges();
    }
  }

  saveNewGift() {
    this.errorMessage = '';
    if (!this.newGift.Name || !this.newGift.Description || !this.newGift.TicketPrice || !this.newGift.DonorId || !this.newGift.Image) {
      this.errorMessage = 'נא למלא את כל שדות החובה לפני השמירה';
      return;
    }

    this.isLoading = true;
    this.giftService.addGift(this.newGift).subscribe({
      next: () => {
        this.displayAddDialog = false;
        this.isLoading = false;
        this.loadGifts();
        this.cdr.detectChanges();
      },
      error: (err) => {
        this.errorMessage = 'Error adding gift';
        this.isLoading = false;
        this.cdr.detectChanges();
      }
    });
  }

  // ---------- Edit Gift ----------
  openEditGiftDialog(gift: GiftModel) {
    this.selectedGiftForEdit = JSON.parse(JSON.stringify(gift));

    setTimeout(() => {
      const categoryObj = this.allCategories.find(c => c.name === gift.category);
      this.selectedGiftForEdit.CategoryId = categoryObj ? categoryObj.id : null;

      // הכי חשוב - למצוא לפי שם מלא
      const donorObj = this.allDonors.find(d => d.fullName === gift.donor);
      this.selectedGiftForEdit.DonorId = donorObj ? donorObj.id : null;

      this.selectedGiftForEdit.Image = gift.image;
      this.selectedGiftForEdit.TicketPrice = gift.ticketPrice;
      this.selectedGiftForEdit.Name = gift.name;

      this.displayEditDialog = true;
      this.cdr.detectChanges();
    }, 0);
  }

  updateGift() {
    const g = this.selectedGiftForEdit;
    if (!g.Name || !g.Description || !g.TicketPrice || !g.DonorId || !g.CategoryId || !g.Image) {
      this.errorMessage = 'נא למלא את כל שדות החובה לפני העדכון';
      return;
    }

    this.errorMessage = '';
    this.giftService.updateGift(g.id, g).subscribe({
      next: () => {
        this.displayEditDialog = false;
        this.loadGifts();
      },
      error: (err) => {
        this.errorMessage = 'אירעה שגיאה בשמירת המתנה.';
        this.cdr.detectChanges();
      }
    });
  }

  // ---------- Other ----------
  GetById(id: number) {
    this.router.navigate(['/gift', id]);
  }
}
<div class="gift-container">
    <div class="header-section">
        <h2>רשימת מתנות זהובה</h2>
        <button *ngIf="isAdmin" class="add-gift-btn" (click)="openAddGiftDialog()">
            <i class="pi pi-plus"></i> הוספת מוצר
        </button>
    </div>

    <!-- overlay למצב טעינה -->
    <div class="overlay" *ngIf="isLoading">
        <div class="spinner"></div>
    </div>

    <ng-container *ngIf="allGifts.length > 0; else loading">
        <div class="gift-grid">
            <div *ngFor="let gift of pagedGifts" class="gift-card" (click)="GetById(gift.id)">
                <div class="image-wrapper">
                    <img [src]="'assets/images/' + gift.image" [alt]="gift.name">
                    <div class="category-badge">{{ gift.category }}</div>

                    <div class="admin-actions" *ngIf="isAdmin">
                        <button class="admin-edit-btn admin-action-btn"
                                (click)="openEditGiftDialog(gift); $event.stopPropagation()">
                            <i class="pi pi-pencil"></i>
                        </button>
                        <button class="admin-delete-btn admin-action-btn"
                                (click)="deleteGift(gift.id); $event.stopPropagation()">
                            <i class="pi pi-trash"></i>
                        </button>
                    </div>
                </div>

                <div class="card-content">
                    <div class="main-info">
                        <h3>{{ gift.name }}</h3>
                        <p class="donor">תורם: {{ gift.donor }}</p>
                        <p class="donor">זוכה: {{ gift.winnerName || 'לא הוגרלה' }}</p>
                    </div>
                    <div class="price-section">
                        <span class="price-label">כרטיס ב-</span>
                        <span class="amount">{{ gift.ticketPrice | currency:'ILS':'symbol':'1.0-0' }}</span>
                    </div>
                    <button class="add-to-cart-btn" style="margin-bottom: 10px;"
                            (click)="raffleGift(gift.id); $event.stopPropagation()">
                        <span>הגרל</span>
                        <i class="pi pi-shopping-cart"></i>
                    </button>

                    <button class="add-to-cart-btn" (click)="addToCart(gift.id); $event.stopPropagation()">
                        <span>הוספה לסל</span>
                        <i class="pi pi-shopping-cart"></i>
                    </button>
                </div>
            </div>
        </div>

        <div class="paginator-wrapper" style="margin-top: 2rem;">
            <div style="direction: ltr;">
                <p-paginator (onPageChange)="onPageChange($event)" [first]="first" [rows]="rows"
                             [totalRecords]="allGifts.length" [rowsPerPageOptions]="[6, 12, 24]">
                </p-paginator>
            </div>
        </div>
    </ng-container>

    <p-dialog header="הוספת מתנה חדשה" [(visible)]="displayAddDialog" [modal]="true" [style]="{ width: '450px' }"
              styleClass="gold-dialog">
        <div class="form-container flex flex-column gap-3">
            <div class="field">
                <label>שם המתנה <span style="color:red">*</span></label>
                <input required type="text" pInputText [(ngModel)]="newGift.Name" class="w-full" />
            </div>
            <div class="field">
                <label>תיאור <span style="color:red">*</span></label>
                <input required type="text" pInputText [(ngModel)]="newGift.Description" class="w-full" />
            </div>
            <div class="field">
                <label>קטגוריה <span style="color:red">*</span></label>
                <select required [(ngModel)]="newGift.CategoryId" class="w-full">
                    <option *ngFor="let category of categories$ | async" [value]="category.id">
                        {{ category.name }}
                    </option>
                </select>
            </div>
            <div class="field">
                <label>מחיר כרטיס <span style="color:red">*</span></label>
                <input required type="number" pInputText [(ngModel)]="newGift.TicketPrice" class="w-full" />
            </div>
            <div class="field">
                <label>תורם <span style="color:red">*</span></label>
                <select required [(ngModel)]="newGift.DonorId" class="w-full" *ngIf="allDonors.length > 0">
                    <option *ngFor="let donor of allDonors" [value]="donor.id">
                        {{ donor.firstName }}
                    </option>
                </select>
                <p *ngIf="allDonors.length === 0">טוען תורמים...</p>
            </div>
            <div class="field">
                <label>תמונה <span style="color:red">*</span></label>
                <p-fileUpload name="image" [auto]="true" (onSelect)="onUpload($event)" />
            </div>
            <small class="p-error" *ngIf="errorMessage">{{errorMessage}}</small>
        </div>
        <ng-template pTemplate="footer">
            <button pButton label="ביטול" class="p-button-text" (click)="displayAddDialog = false"></button>
            <button pButton label="שמירה" icon="pi pi-check" (click)="saveNewGift()"></button>
        </ng-template>
    </p-dialog>

    <p-dialog header="עריכת מתנה" [(visible)]="displayEditDialog" [modal]="true" [style]="{ width: '450px' }"
              styleClass="gold-dialog">
        <div class="form-container flex flex-column gap-3">
            <div class="field">
                <label>שם המתנה <span style="color:red">*</span></label>
                <input type="text" pInputText [(ngModel)]="selectedGiftForEdit.Name" class="w-full" />
            </div>
            <div class="field">
                <label>תיאור <span style="color:red">*</span></label>
                <textarea pInputTextarea [(ngModel)]="selectedGiftForEdit.Description" class="w-full"></textarea>
            </div>
            <div class="field">
                <label>קטגוריה <span style="color:red">*</span></label>
                <select required [(ngModel)]="selectedGiftForEdit.CategoryId" class="w-full">
                    <option *ngFor="let category of categories$ | async" [value]="category.id">
                        {{ category.name }}
                    </option>
                </select>
            </div>
            <div class="field">
                <label>מחיר כרטיס <span style="color:red">*</span></label>
                <input type="number" pInputText [(ngModel)]="selectedGiftForEdit.TicketPrice" class="w-full" />
            </div>
            <div class="field">
                <label>תורם <span style="color:red">*</span></label>
                <select required [(ngModel)]="selectedGiftForEdit.DonorId" class="w-full" *ngIf="allDonors.length > 0">
                    <option *ngFor="let donor of allDonors" [value]="donor.id">
                        {{ donor.firstName }}
                    </option>
                </select>
                <p *ngIf="allDonors.length === 0">טוען תורמים...</p>
            </div>
            <div class="field">
                <label>תמונה <span style="color:red">*</span></label>
                <p-fileUpload name="image" [auto]="true" (onSelect)="onUpload($event)" />
            </div>
        </div>
        <ng-template pTemplate="footer">
            <button pButton label="ביטול" class="p-button-text" (click)="displayEditDialog = false"></button>
            <button pButton label="עדכן שינויים" icon="pi pi-check" (click)="updateGift()"></button>
        </ng-template>
    </p-dialog>

    <ng-template #loading>
        <div class="loading-state" style="text-align: center; padding: 50px;">
            <p-progressSpinner></p-progressSpinner>
            <p>טוען את הגלריה היוקרתית...</p>
        </div>
    </ng-template>
</div>
